#include<bits/stdc++.h>
using namespace std;
int w[500010];
long long dfn[500010],fa[500010],d[500010],siz[500010],son[500010],top[500010],dfncnt,val[500010],rnk[500010];
vector<long long> mp[500010];
void dfs1(long long x,long long f=0)
{
    son[x]=-1;
    siz[x]=1;
    for(long long i:mp[x])
    {
        if(i!=f)
        {
            fa[i]=x;
            d[i]=d[x]+1;
            dfs1(i,x);
            siz[x]+=siz[i];
            if(son[x]==-1||siz[i]>siz[son[x]])
            {
                son[x]=i;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfncnt]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(long long i:mp[x])
        {
            if(i!=son[x]&&i!=fa[x])
            {
                dfs2(i,i);
            }
        }
    }
}
long long Lc,Rc;
struct segment_tree
{
	struct node
	{
		long long l,r,num,lc,rc;
		long long lson,rson;
		long long tag;
		node():tag(0){}
	}a[1500010];
	long long cnt;
	segment_tree():cnt(0){}
	void pushup(long long x)
	{
		a[x].lc=a[a[x].lson].lc;
        a[x].rc=a[a[x].rson].rc;
        a[x].num=a[a[x].lson].num+a[a[x].rson].num-(a[a[x].lson].rc==a[a[x].rson].lc);
	}
	void pushdown(long long x)
	{
        if(a[x].tag==0)
        {
            return;
        }
		long long mid=(a[x].l+a[x].r)>>1;
		long long ls=a[x].lson,rs=a[x].rson;
		long long tg=a[x].tag;
		a[ls].num=a[rs].num=1;
        a[ls].lc=a[ls].rc=a[rs].lc=a[rs].rc=tg;
		a[ls].tag=tg;
		a[rs].tag=tg;
		a[x].tag=0;
	}
	long long init(long long l,long long r)
	{
		long long x=++cnt,mid=(l+r)>>1;
		a[x].l=l;
		a[x].r=r;
        a[x].num=0;
		if(l==r)
		{
			return x;
		}
		a[x].lson=init(l,mid);
		a[x].rson=init(mid+1,r);
		return x;
	}
	void update(long long x,long long l,long long r,long long z)
	{
		if(l==a[x].l&&a[x].r==r)
		{
			a[x].tag=a[x].lc=a[x].rc=z;
            a[x].num=1;
			return;
		}
		pushdown(x);
        int mid=(a[x].l+a[x].r)/2;
		if(r<=mid)
        {
            update(a[x].lson,l,r,z);
        }
        else if(l>mid)
        {
            update(a[x].rson,l,r,z);
        }
        else
        {
            update(a[x].lson,l,mid,z);
            update(a[x].rson,mid+1,r,z);
        }
		pushup(x);
	}
	long long query(long long x,long long l,long long r,long long u,long long v)
	{
        if(a[x].l==u)
        {
            Lc=a[x].lc;
        }
        if(a[x].r==v)
        {
            Rc=a[x].rc;
        }
        if(a[x].l==l&&a[x].r==r)
        {
            return a[x].num;
        }
		pushdown(x);
        int mid=(a[x].l+a[x].r)/2;
		if(r<=mid)
        {
            return query(a[x].lson,l,r,u,v);
        }
        else if(l>mid)
        {
            return query(a[x].rson,l,r,u,v);
        }
        else
        {
            return query(a[x].lson,l,mid,u,v)+query(a[x].rson,mid+1,r,u,v)-(a[a[x].lson].rc==a[a[x].rson].lc);
        }
	}
}t;
void update(int u,int v,int c)
{
    while(top[u]!=top[v])
    {
        if(d[top[u]]<d[top[v]])
        {
            swap(u,v);
        }
        t.update(1,dfn[top[u]],dfn[u],c);
        u=fa[top[u]];
    }
    if(d[u]>d[v])
    {
        swap(u,v);
    }
    t.update(1,dfn[u],dfn[v],c);
}
int query(int u,int v)
{
    int ans=0,ans1=-1,ans2=-1;
    while(top[u]!=top[v])
    {
        if(d[top[u]]<d[top[v]])
        {
            swap(u,v);
            swap(ans1,ans2);
        }
        ans+=t.query(1,dfn[top[u]],dfn[u],dfn[top[u]],dfn[u]);
        if(Rc==ans1)
        {
            ans--;
        }
        ans1=Lc;
        u=fa[top[u]];
    }
    if(d[u]<d[v])
    {
        swap(u,v);
        swap(ans1,ans2);
    }
    ans+=t.query(1,dfn[v],dfn[u],dfn[v],dfn[u]);
    ans-=(Rc==ans1)+(Lc==ans2);
    return ans;
}
int c[500010];
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&c[i]);
    }
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs1(1);
    dfs2(1,1);
    t.init(1,n);
    for(int i=1;i<=n;i++)
    {
        t.update(1,dfn[i],dfn[i],c[i]);
    }
    while(m--)
    {
        char ch;
        int u,v,c;
        cin>>ch;
        scanf("%d%d",&u,&v);
        if(ch=='C')
        {
            scanf("%d",&c);
            update(u,v,c);
        }
        else
        {
            printf("%d\n",query(u,v));
        }
    }
    return 0;
}
